package test;

import org.eclipse.jdt.core.SignatureUtil;
import org.eclipse.jdt.core.Signature;

public class Example {
    String getDeclaringType(String declaringTypeSignature) {
        if (declaringTypeSignature == null) {
            return "java.lang.Object";
        }
        return SignatureUtil.stripSignatureToFQN(String.valueOf(declaringTypeSignature));
    }
}

afterExample:
package test;

import org.eclipse.jdt.core.SignatureUtil;
import org.eclipse.jdt.core.Signature;

public class Example {
    String getDeclaringType(String declaringTypeSignature) {
        if (declaringTypeSignature == null) {
            return "java.lang.Object";
        }
        return Signature.toString(Signature.getTypeErasure(String.valueOf(declaringTypeSignature)));
    }
}

negativeExample:
package test;

import org.eclipse.jdt.core.SignatureUtil;
import org.eclipse.jdt.core.Signature;

public class Example {
    String someOtherOperation(String signature) {
        // This method call has a different argument ($signature directly, not String.valueOf($var))
        String stripped = SignatureUtil.stripSignatureToFQN(signature);
        // This method call uses Signature.toString directly, not after getTypeErasure
        String toString = Signature.toString(signature);
        return stripped + toString;
    }
}
